      'copyrightNotice' => 
      array (
        'label' => 'Copyright Notice',
        'type' => 'text',
        'comment' => 'Text of a notice appropriate for describing the copyright aspects of this Creative Work, ideally indicating the owner of the copyright for the Work.',
