      'correctionsPolicy' => 
      array (
        'label' => 'Corrections Policy',
        'type' => 'url',
        'comment' => 'For an Organization (e.g. NewsMediaOrganization), a statement describing (in news media, the newsroom’s) disclosure and correction policy for errors.',
      ),
      'description' => 
      array (
        'label' => 'Description',
        'type' => 'text',
