        'label' => 'Production Date',
        'type' => 'date',
        'comment' => 'The date of production of the item, e.g. vehicle.',
      ),
      'purchaseDate' => 
      array (
        'label' => 'Purchase Date',
        'type' => 'date',
        'comment' => 'The date the item, e.g. vehicle, was purchased by the current owner.',
